import axios from 'axios';

const API_URL = 'http://localhost:5000/api';

const api = axios.create({
  baseURL: API_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// 🔐 Attach token to every request (SAFE)
api.interceptors.request.use(
  (config) => {
    try {
      const token = localStorage.getItem('token');
      if (token) {
        config.headers.Authorization = `Bearer ${token}`;
      }
    } catch (err) {
      console.error('Token attach error:', err);
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// 🚨 Handle response errors globally (NO breaking change)
api.interceptors.response.use(
  (response) => response,
  (error) => {
    // Optional: auto logout if token expired
    if (error?.response?.status === 401) {
      console.warn('Unauthorized - possible token expiry');
      // You can trigger logout here later if needed
    }
    return Promise.reject(error);
  }
);


// 🔐 AUTH APIs (UNCHANGED + CLEAN)
export const authAPI = {
  login: (username, password) =>
    api.post('/auth/login', { username, password }),

  signup: (data) =>
    api.post('/auth/signup', data),
};


// 📌 TASK APIs (UNCHANGED)
export const tasksAPI = {
  getTasks: (search = '', department = '') =>
    api.get('/tasks', { params: { search, department } }),

  getTask: (id) => api.get(`/tasks/${id}`),

  createTask: (data) => api.post('/tasks', data),

  updateTask: (id, data) => api.put(`/tasks/${id}`, data),

  deleteTask: (id) => api.delete(`/tasks/${id}`),
};


// 📊 MIS APIs (UNCHANGED)
export const misAPI = {
  getStats: () => api.get('/mis'),
};

export default api;
